    """测试已知哈希值图片"""
    print("=" * 60)
    print("测试已知哈希值图片过滤")
    print("=" * 60)

    digest = ByHandDigestMock()

    # 用户提到的哈希值图片
    test_url = "https://substack-post-media.s3.amazonaws.com/public/images/8dcdc34ae1e0181dcf5ed89469409f42.jpg"

    # 模拟img元素
    class MockImgElement:
        def __init__(self, attrs=None):
            self.attrs = attrs or {}

        def get(self, key, default=None):
            return self.attrs.get(key, default)

    img_element = MockImgElement({
        'src': test_url,
        'alt': '文章插图',
        'class': ['content-image']
    })

    result = digest._is_article_image(test_url, img_element)
    print(f"\n测试结果: {result}")
    print(f"URL: {test_url}")
    print(f"预期: True (因为已修复过滤逻辑)")

    if result:
        print("\n✓ 修复成功：已知哈希值图片不再被错误过滤")
    else:
        print("\n✗ 修复失败：图片仍被过滤")

    return result

def test_various_images():
    """测试各种类型图片"""
    print("\n" + "=" * 60)
    print("测试各种类型图片过滤")
    print("=" * 60)

    digest = ByHandDigestMock()

    test_cases = [
        {
            'url': 'https://substackcdn.com/image/fetch/w_80,h_80,c_fill,g_face,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fbucketeer-e05bbc84-baa3-437e-9518-adb32be77984.s3.amazonaws.com%2Fpublic%2Fimages%2Ff8165e5c-7b95-4d5f-a2d8-17a4c5d4e9d5_500x500.png',
            'attrs': {'src': '', 'class': ['avatar'], 'alt': '用户头像', 'width': '80', 'height': '80'},
            'description': '头像图片',
            'expected': False
        },
        {
            'url': 'https://substack-post-media.s3.amazonaws.com/public/images/abc123def456.jpg',
            'attrs': {'src': '', 'alt': '神经网络架构图', 'class': ['content-image']},
            'description': '正常文章图片',
            'expected': True
        },
        {
            'url': 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8z8BQDwAEhQGAhKmMIQAAAABJRU5ErkJggg==',
            'attrs': {'src': '', 'alt': ''},
            'description': '数据URI',
            'expected': False
        }
    ]

    results = []
    for test_case in test_cases:
        class MockImgElement:
            def __init__(self, attrs):
                self.attrs = attrs

            def get(self, key, default=None):
                return self.attrs.get(key, default)

        img_element = MockImgElement(test_case['attrs'])
        img_element.attrs['src'] = test_case['url']  # 设置实际URL

        print(f"\n测试: {test_case['description']}")
        result = digest._is_article_image(test_case['url'], img_element)
        status = "✓" if result == test_case['expected'] else "✗"
        print(f"  {status} 结果: {result} (预期: {test_case['expected']})")

        results.append(result == test_case['expected'])

